    /**
     * Global interceptor that catches any unhandled exceptions and ensures
     * they are sanitized before reaching the client.
     * This is a safety net — individual handlers should use SecureErrorResponseBuilder.
     */
    public static class SecureErrorInterceptor implements ServerInterceptor {

        private static final Logger interceptorLogger =
                LoggerFactory.getLogger(SecureErrorInterceptor.class);

        @Override
        public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
                ServerCall<ReqT, RespT> call,
                Metadata headers,
                ServerCallHandler<ReqT, RespT> next) {

            ServerCall<ReqT, RespT> wrappedCall = new ForwardingServerCall.SimpleForwardingServerCall<ReqT, RespT>(call) {
                @Override
                public void close(io.grpc.Status status, Metadata trailers) {
                    if (status.getCode() != io.grpc.Status.Code.OK) {
                        // Ensure no internal details leak through the status description
                        io.grpc.Status safeStatus = sanitizeStatus(status);
                        super.close(safeStatus, sanitizeTrailers(trailers));
                    } else {
                        super.close(status, trailers);
                    }
                }
            };

            ServerCall.Listener<ReqT> listener;
            try {
                listener = next.startCall(wrappedCall, headers);
            } catch (Exception e) {
                String correlationId = ErrorCorrelationId.generate();
                interceptorLogger.error("Unhandled exception in call setup [{}]: {}",
                        correlationId, e.getMessage(), e);

                call.close(
                        io.grpc.Status.INTERNAL.withDescription(
                                "Internal error. Correlation ID: " + correlationId),
                        new Metadata());
                return new ServerCall.Listener<ReqT>() {};
            }

            return new ForwardingServerCallListener.SimpleForwardingServerCallListener<ReqT>(listener) {
                @Override
                public void onHalfClose() {
                    try {
                        super.onHalfClose();
                    } catch (StatusRuntimeException e) {
                        // Already a StatusRuntimeException — check if it's from our builder
                        // (contains ErrorInfo with correlation_id) or raw
                        if (isAlreadySanitized(e)) {
                            call.close(e.getStatus(), e.getTrailers() != null ? e.getTrailers() : new Metadata());
                        } else {
                            String correlationId = ErrorCorrelationId.generate();
                            interceptorLogger.error("Unsanitized StatusRuntimeException [{}]: {}",
                                    correlationId, e.getMessage(), e);
                            call.close(
                                    io.grpc.Status.INTERNAL.withDescription(
                                            "Internal error. Correlation ID: " + correlationId),
                                    new Metadata());
                        }
                    } catch (Exception e) {
                        String correlationId = ErrorCorrelationId.generate();
                        interceptorLogger.error("Unhandled exception in onHalfClose [{}]: {}",
                                correlationId, e.getMessage(), e);
                        call.close(
                                io.grpc.Status.INTERNAL.withDescription(
                                        "Internal error. Correlation ID: " + correlationId),
                                new Metadata());
                    }
                }

                @Override
                public void onMessage(ReqT message) {
                    try {
                        super.onMessage(message);
                    } catch (Exception e) {
                        String correlationId = ErrorCorrelationId.generate();
                        interceptorLogger.error("Unhandled exception in onMessage [{}]: {}",
                                correlationId, e.getMessage(), e);
                        call.close(
                                io.grpc.Status.INTERNAL.withDescription(
                                        "Internal error. Correlation ID: " + correlationId),
                                new Metadata());
                    }
                }
            };
        }

        private io.grpc.Status sanitizeStatus(io.grpc.Status status) {
            String description = status.getDescription();
            if (description != null && containsSensitiveInfo(description)) {
                String correlationId = ErrorCorrelationId.generate();
                interceptorLogger.warn(
                        "Sanitized potentially sensitive status description [{}]: original={}",
                        correlationId, description);
                return status.getCode().toStatus()
                        .withDescription("An error occurred. Correlation ID: " + correlationId);
            }
            return status;
        }

        private Metadata sanitizeTrailers(Metadata trailers) {
            // Remove any keys that might contain sensitive data
            // Keep only well-known safe keys
            return trailers != null ? trailers : new Metadata();
        }

        private boolean containsSensitiveInfo(String text) {
            if (text == null) return false;
            String lower = text.toLowerCase();
            return lower.contains("stacktrace") ||
                    lower.contains("exception") ||
                    lower.contains("sql") ||
                    lower.contains("jdbc") ||
                    lower.contains("password") ||
                    lower.contains("token") ||
                    lower.contains("secret") ||
                    lower.contains("at com.") ||
                    lower.contains("at java.") ||
                    lower.contains("at io.") ||
                    lower.contains("caused by:") ||
                    lower.contains("table ") ||
                    lower.contains("column ") ||
                    lower.contains("constraint") ||
                    lower.contains("connection refused") ||
                    lower.contains("host=") ||
                    lower.contains("port=");
        }

        private boolean isAlreadySanitized(StatusRuntimeException e) {
            // Check if the exception was created by our SecureErrorResponseBuilder
            // by looking for our domain in ErrorInfo
            io.grpc.Status status = e.getStatus();
            if (status.getDescription() != null &&
                    status.getDescription().contains("Correlation ID:")) {
                return true;
            }
            Metadata trailers = e.getTrailers();
            if (trailers != null) {
                byte[] statusBytes = trailers.get(
                        Metadata.Key.of("grpc-status-details-bin", Metadata.BINARY_BYTE_MARSHALLER));
                if (statusBytes != null) {
                    try {
                        Status rpcStatus = Status.parseFrom(statusBytes);
                        for (Any detail : rpcStatus.getDetailsList()) {
                            if (detail.is(ErrorInfo.class)) {
                                ErrorInfo errorInfo = detail.unpack(ErrorInfo.class);
                                if ("com.example.grpc".equals(errorInfo.getDomain()) &&
                                        errorInfo.getMetadataMap().containsKey("correlation_id")) {
                                    return true;
                                }
                            }
                        }
                    } catch (Exception ignored) {
                        // If we can't parse, treat as unsanitized
                    }
                }
            }
            return false;
        }
    }

